// Parse and structure the scraped data
const mention = {
  title: item.title || item.story_title || 'No title',
  content: item.content || item.text || item.description || '',
  url: item.url || item.story_url || '',
  source: item.source || 'Unknown',
  source_type: 'NEWS_WEBSITE',
  author: item.author || item.by || null,
  published_at: item.created_at || item.published || new Date().toISOString(),
  person_name: $node["webhook-trigger"].json["person_name"],
  company: $node["webhook-trigger"].json["company"],
  job_title: $node["webhook-trigger"].json["job_title"],
  scraped_by: 'n8n',
  status: 'NEW'
};

// Basic sentiment analysis
const positiveWords = ['excellent', 'great', 'innovative', 'success', 'leader', 'growth', 'achievement'];
const negativeWords = ['concern', 'issue', 'problem', 'failure', 'decline', 'criticism', 'controversy'];

const text = (mention.title + ' ' + mention.content).toLowerCase();
let positiveCount = 0;
let negativeCount = 0;

positiveWords.forEach(word => {
  if (text.includes(word)) positiveCount++;
});

negativeWords.forEach(word => {
  if (text.includes(word)) negativeCount++;
});

if (positiveCount > negativeCount) {
  mention.sentiment = 'POSITIVE';
  mention.sentiment_score = 0.7 + (positiveCount * 0.05);
} else if (negativeCount > positiveCount) {
  mention.sentiment = 'NEGATIVE';
  mention.sentiment_score = 0.3 - (negativeCount * 0.05);
} else {
  mention.sentiment = 'NEUTRAL';
  mention.sentiment_score = 0.5;
}

// Extract keywords
const keywords = [];
if (text.includes('ceo')) keywords.push('CEO');
if (text.includes('technology')) keywords.push('technology');
if (text.includes('startup')) keywords.push('startup');
if (text.includes('funding')) keywords.push('funding');
if (text.includes('product')) keywords.push('product');
if (text.includes('musso')) keywords.push('Musso');

mention.keywords = keywords;

return mention;
